import json

def read_jsonl(path, encoding="utf-8"):
    """逐行读取 .jsonl 文件，返回一个生成器（每行一个 dict）。"""
    with open(path, "r", encoding=encoding) as f:
        for lineno, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                yield json.loads(line)
            except json.JSONDecodeError as e:
                raise ValueError(f"JSON 解析失败：{path} 第 {lineno} 行：{e}") from e

# 用法示例
if __name__ == "__main__":
    for obj in read_jsonl("data.jsonl"):
        print(obj)
```

如果你想一次性读成列表，把 `yield` 的结果包一层：`data = list(read_jsonl("data.jsonl"))`。
